// 🔒 Detecta DevTools abiertas
(function detectDevTools() {
    let devtoolsOpen = false;
    const element = new Image();
    Object.defineProperty(element, 'id', {
      get: function () {
        devtoolsOpen = true;
        throw new Error('DevTools detected');
      }
    });
  
    setInterval(() => {
      devtoolsOpen = false;
      console.dir(element);
      if (devtoolsOpen) {
        alert('⚠️ Esta acción no está permitida.');
        window.location.href = 'about:blank'; // o window.close();
      }
    }, 1000);
  })();
  
  // 🛑 Bloquea clic derecho, arrastrar, seleccionar texto
  document.addEventListener('contextmenu', e => e.preventDefault());
  document.addEventListener('dragstart', e => e.preventDefault());
  document.addEventListener('selectstart', e => e.preventDefault());
  
  // 🚫 Bloquea F12, Ctrl+Shift+I/J/C, Ctrl+U, Ctrl+S
  document.addEventListener('keydown', function (e) {
    if (
      e.key === 'F12' ||
      (e.ctrlKey && e.shiftKey && ['I', 'J', 'C'].includes(e.key.toUpperCase())) ||
      (e.ctrlKey && ['U', 'S'].includes(e.key.toUpperCase()))
    ) {
      e.preventDefault();
      alert('🚫 Acción bloqueada.');
    }
  });
  